PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT ?horse ?position
WHERE {
  {
    SELECT ?edition ?date
    WHERE {
      ?edition wdt:P361 wd:Q1542651 ;
               wdt:P585 ?date .
    }
    ORDER BY DESC(?date)
    LIMIT 1
  }
  ?edition p:P710 [ ps:P710 ?horse ; pq:P1352 ?position ] .
}
ORDER BY ?position

PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX pq: <http://www.wikidata.org/prop/qualifier/>

SELECT ?horse ?position
WHERE {
  {
    SELECT ?edition
    WHERE {
      ?edition wdt:P361 wd:Q1542651 ;
               wdt:P585 ?date .
      FILTER (isLiteral(?date))
    }
    ORDER BY DESC(?date)
    LIMIT 1
  }
  ?edition p:P710 [ ps:P710 ?horse ; pq:P1352 ?position ] .
}
ORDER BY ?position
LIMIT 3

